/* ==========================================================================
   Base Design System - Protocodus
   ========================================================================== */
:root {
  /* Colors based on Logo */
  --clr-bg: #FAFAFA;
  --clr-text: #1A1A1A;
  --clr-yellow: #FFC400;
  --clr-mint: #00FFC3;
  --clr-black: #1A1A1A;
  --clr-white: #FFFFFF;
  --clr-grey: #888888;

  /* Typography */
  --font-primary: 'Space Grotesk', sans-serif;

  /* Layout & Spacing */
  --container-width: 1120px;
  --space-sm: 1rem;
  --space-md: 2rem;
  --space-lg: 4rem;
  --space-xl: 7rem;

  /* Aesthetics */
  --border-radius: 0px;
  --border-radius-pill: 999px;
  --border-width: 2.5px;
  --shadow-solid: 5px 5px 0px var(--clr-black);
  --shadow-solid-hover: 2px 2px 0px var(--clr-black);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Base Reset */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-primary);
  color: var(--clr-text);
  line-height: 1.7;
  overflow-x: hidden;
}

/* Animated Background (p5.js) */
.bg-animation-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  z-index: -1;
  overflow: hidden;
  pointer-events: none;
  background-color: var(--clr-bg);
}

.bg-animation-container canvas {
  display: block;
  width: 100% !important;
  height: 100% !important;
}

a {
  text-decoration: none;
  color: inherit;
}

ul {
  list-style: none;
}

img,
svg {
  max-width: 100%;
  display: block;
}

.container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: 0 var(--space-md);
}

.section {
  padding: var(--space-xl) 0;
}

/* ==========================================================================
   Scroll Reveal Animation
   ========================================================================== */
.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s cubic-bezier(0.16, 1, 0.3, 1),
    transform 0.8s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* Stagger children */
.bento-grid .reveal:nth-child(2) {
  transition-delay: 0.1s;
}

.bento-grid .reveal:nth-child(3) {
  transition-delay: 0.2s;
}

.bento-grid .reveal:nth-child(4) {
  transition-delay: 0.3s;
}

/* ==========================================================================
   Buttons
   ========================================================================== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.9rem 2rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  border: var(--border-width) solid var(--clr-black);
  transition: var(--transition);
  font-size: 0.85rem;
  font-family: var(--font-primary);
  cursor: pointer;
}

.btn-primary {
  background-color: var(--clr-yellow);
  color: var(--clr-black);
  box-shadow: var(--shadow-solid);
}

.btn-primary:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-mint);
}

.btn-outline {
  background-color: var(--clr-white);
  color: var(--clr-black);
  box-shadow: var(--shadow-solid);
}

.btn-outline:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-yellow);
}

.btn-lg {
  font-size: 1.05rem;
  padding: 1.1rem 2.5rem;
}

/* ==========================================================================
   Navbar
   ========================================================================== */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  background-color: rgba(250, 250, 250, 0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: var(--border-width) solid var(--clr-black);
  z-index: 1000;
  transition: var(--transition);
}

.navbar.scrolled {
  padding: 0;
}

.nav-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 80px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.logo-img {
  height: 52px;
  width: auto;
}

.logo-text {
  font-size: 1.3rem;
  font-weight: 800;
  letter-spacing: 2px;
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 2.5rem;
}

.nav-link {
  font-weight: 600;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  position: relative;
  padding: 0.5rem 0;
  color: var(--clr-text);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0%;
  height: 2.5px;
  background-color: var(--clr-yellow);
  transition: var(--transition);
}

.nav-link:hover::after {
  width: 100%;
}

.nav-btn {
  background-color: var(--clr-yellow);
  padding: 0.65rem 1.5rem;
  border: var(--border-width) solid var(--clr-black);
  font-weight: 700;
  box-shadow: 3px 3px 0px var(--clr-black);
  transition: var(--transition);
  text-transform: uppercase;
  font-size: 0.8rem;
  letter-spacing: 1px;
}

.nav-btn:hover {
  box-shadow: 1px 1px 0px var(--clr-black);
  transform: translate(2px, 2px);
  background-color: var(--clr-mint);
}

.mobile-menu-btn {
  display: none;
  background: none;
  border: none;
  flex-direction: column;
  gap: 6px;
  cursor: pointer;
  padding: 8px;
}

.mobile-menu-btn span {
  display: block;
  width: 28px;
  height: 2.5px;
  background-color: var(--clr-black);
  transition: var(--transition);
  pointer-events: none;
}

/* ==========================================================================
   Hero Section
   ========================================================================== */
.hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding-top: 80px;
  position: relative;
  overflow: hidden;
}

.hero-container {
  display: flex;
  justify-content: center;
  position: relative;
  z-index: 1;
}

.hero-content {
  max-width: 680px;
}

.hero-title {
  font-size: 5.5rem;
  font-weight: 900;
  line-height: 1.05;
  margin-bottom: 1.5rem;
  letter-spacing: -3px;
  color: var(--clr-black);
}

.hero-subtitle {
  font-size: 1.2rem;
  font-weight: 400;
  max-width: 520px;
  margin-bottom: 2.5rem;
  color: #555;
  line-height: 1.8;
}

.hero-actions {
  display: flex;
  gap: 1.25rem;
}

/* ==========================================================================
   Section Headers
   ========================================================================== */
.section-header {
  text-align: center;
  margin-bottom: 3.5rem;
}

.section-title {
  font-size: 3rem;
  font-weight: 900;
  margin-bottom: 1rem;
  display: inline-block;
  position: relative;
  letter-spacing: -1px;
}

.section-title::after {
  content: '';
  position: absolute;
  bottom: 6px;
  left: -6px;
  right: -6px;
  height: 35%;
  background-color: var(--clr-mint);
  z-index: -1;
  opacity: 0.6;
}

.section-desc {
  font-size: 1.1rem;
  max-width: 560px;
  margin: 0 auto;
  color: #555;
  line-height: 1.8;
}

/* ==========================================================================
   Bento Grid — Services
   ========================================================================== */
.bento-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1.75rem;
}

.bento-card {
  background-color: var(--clr-white);
  border: var(--border-width) solid var(--clr-black);
  padding: 2.5rem;
  display: flex;
  flex-direction: column;
  box-shadow: var(--shadow-solid);
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.bento-card:hover {
  transform: translateY(-4px);
  box-shadow: 8px 8px 0px var(--clr-black);
}

.bento-card.bg-yellow {
  background-color: var(--clr-yellow);
}

.bento-card.bg-mint {
  background-color: var(--clr-mint);
}

.bento-icon {
  font-size: 2.5rem;
  margin-bottom: 1.25rem;
  color: var(--clr-black);
}

.bento-card h3 {
  font-size: 1.6rem;
  font-weight: 800;
  margin-bottom: 0.75rem;
  line-height: 1.2;
}

.bento-card p {
  font-size: 1rem;
  line-height: 1.7;
  margin-bottom: 0;
  flex-grow: 1;
  color: rgba(26, 26, 26, 0.8);
}

.bento-card.bg-yellow p,
.bento-card.bg-mint p {
  color: rgba(26, 26, 26, 0.85);
}

/* ==========================================================================
   About Section
   ========================================================================== */
.about-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
}

.about-desc {
  font-size: 1.1rem;
  margin-bottom: 2rem;
  color: #444;
  line-height: 1.8;
}

.about-list {
  margin-bottom: 2rem;
}

.about-list li {
  font-size: 1.05rem;
  margin-bottom: 0.75rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-weight: 500;
}

.check-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  background-color: var(--clr-mint);
  border: 2px solid var(--clr-black);
  font-weight: 800;
  font-size: 0.75rem;
  flex-shrink: 0;
}

/* About Stats Card */
.about-stats-card {
  background-color: var(--clr-black);
  color: var(--clr-white);
  border: var(--border-width) solid var(--clr-black);
  padding: 3rem 2.5rem;
  box-shadow: 8px 8px 0px var(--clr-yellow);
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

.stat-item {
  text-align: center;
}

.stat-number {
  display: block;
  font-size: 3.5rem;
  font-weight: 900;
  letter-spacing: -2px;
  line-height: 1;
  margin-bottom: 0.5rem;
  color: var(--clr-yellow);
}

.stat-label {
  display: block;
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: rgba(255, 255, 255, 0.7);
}

.stat-divider {
  width: 40px;
  height: 2px;
  background-color: var(--clr-mint);
  margin: 0 auto;
  opacity: 0.5;
}

.mt-2 {
  margin-top: 2rem;
}

/* ==========================================================================
   Contact Section
   ========================================================================== */
.bg-dark {
  background-color: var(--clr-black);
  color: var(--clr-white);
}

.title-light {
  color: var(--clr-white);
}

.title-light::after {
  background-color: var(--clr-mint);
  opacity: 0.35;
}

.contact-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 2.5rem;
  padding: 3rem 0;
}

.contact-name {
  font-size: 1.3rem;
  font-weight: 700;
  margin-bottom: 0.35rem;
}

.contact-role {
  color: var(--clr-mint);
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 3px;
  font-size: 0.8rem;
  margin-bottom: 1.75rem;
}

.contact-header p {
  font-size: 1.15rem;
  opacity: 0.85;
}

/* ==========================================================================
   Footer
   ========================================================================== */
.footer {
  border-top: var(--border-width) solid var(--clr-black);
  padding: 3rem 0 1.5rem;
  background-color: var(--clr-white);
}

.footer-container {
  display: grid;
  grid-template-columns: 1fr;
  margin-bottom: 2rem;
}

.footer-brand {
  text-align: center;
}

.footer-logo {
  justify-content: center;
}

.footer-logo-text {
  font-size: 1.8rem;
  letter-spacing: 3px;
}

.footer-tagline {
  margin: 0.75rem auto 0;
  font-size: 0.95rem;
  color: var(--clr-grey);
}

.footer-bottom {
  display: flex;
  justify-content: center;
  align-items: center;
  padding-top: 1.5rem;
  border-top: 1.5px solid rgba(26, 26, 26, 0.12);
  font-weight: 500;
  font-size: 0.85rem;
  color: var(--clr-grey);
}

.footer-centered {
  grid-template-columns: 1fr;
  text-align: center;
}

.footer-bottom-centered {
  display: block;
  text-align: center;
}

/* ==========================================================================
   Media Queries
   ========================================================================== */
@media (max-width: 992px) {

  .hero-container,
  .about-container,
  .contact-container,
  .footer-container {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-content {
    text-align: center;
    margin: 0 auto;
  }

  .hero-subtitle {
    margin-left: auto;
    margin-right: auto;
  }

  .about-list li {
    justify-content: center;
  }

  .hero-actions {
    justify-content: center;
  }

  .hero-title {
    font-size: 3.5rem;
  }

  .bento-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .about-stats-card {
    flex-direction: row;
    justify-content: center;
    max-width: 500px;
    margin: 0 auto;
  }

  .stat-divider {
    width: 2px;
    height: 40px;
  }
}

@media (max-width: 768px) {
  .nav-container .logo-img {
    display: none;
  }

  .nav-links {
    display: none;
  }

  .nav-links.active {
    display: flex;
    flex-direction: column;
    position: absolute;
    top: 100%;
    left: 0;
    width: 100%;
    background-color: rgba(250, 250, 250, 0.98);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    padding: 2rem;
    border-bottom: var(--border-width) solid var(--clr-black);
    align-items: center;
    gap: 1.5rem;
    z-index: 999;
  }

  .mobile-menu-btn {
    display: flex;
    position: relative;
    z-index: 1000;
  }

  .mobile-menu-btn.active span:nth-child(1) {
    transform: translateY(8.5px) rotate(45deg);
  }

  .mobile-menu-btn.active span:nth-child(2) {
    opacity: 0;
  }

  .mobile-menu-btn.active span:nth-child(3) {
    transform: translateY(-8.5px) rotate(-45deg);
  }

  .hero-title {
    font-size: 2.8rem;
    letter-spacing: -1.5px;
  }

  .section-title {
    font-size: 2rem;
  }

  .bento-grid {
    grid-template-columns: 1fr;
  }

  .about-stats-card {
    flex-direction: column;
    max-width: 100%;
  }

  .stat-divider {
    width: 40px;
    height: 2px;
  }

  .footer-logo-text {
    font-size: 1.5rem;
  }

  .footer-bottom {
    flex-direction: column;
    gap: 0.75rem;
    text-align: center;
  }

  .btn-lg {
    font-size: 0.9rem;
    padding: 0.9rem 1.5rem;
  }
}

@media (max-width: 480px) {
  .hero-title {
    font-size: 2.2rem;
    letter-spacing: -1px;
  }

  .hero-subtitle {
    font-size: 1rem;
  }

  .hero-actions {
    flex-direction: column;
    gap: 0.75rem;
  }

  .bento-card {
    padding: 1.75rem;
  }

  .section {
    padding: 4rem 0;
  }
}

