    19→    const navLinks = document.querySelector('.nav-links');
    20→    
    21→    if (mobileMenuBtn && navLinks) {
    22→        mobileMenuBtn.addEventListener('click', () => {
    23→            mobileMenuBtn.classList.toggle('active');
    24→            navLinks.classList.toggle('active');
    25→        });
    26→        
    27→        const links = navLinks.querySelectorAll('a');
    28→        links.forEach(link => {
    29→            link.addEventListener('click', () => {
    30→                mobileMenuBtn.classList.remove('active');
    31→                navLinks.classList.remove('active');
    32→            });
    33→        });
    34→    }
    35→
    36→    // =========================================================================
    37→    // Scroll Reveal
    38→    // =========================================================================
    39→    const revealEls = document.querySelectorAll('.reveal');
    40→    
    41→    const revealObserver = new IntersectionObserver((entries) => {
    42→        entries.forEach(entry => {
    43→            if (entry.isIntersecting) {
    44→                entry.target.classList.add('visible');
    45→                revealObserver.unobserve(entry.target);
    46→            }
    47→        });
    48→    }, {
    49→        threshold: 0.15,
    50→        rootMargin: '0px 0px -40px 0px'
    51→    });
    52→
    53→    revealEls.forEach(el => revealObserver.observe(el));
    54→
    55→    // =========================================================================
    56→    // p5.js Background — Elegant Perlin Noise Flow Field
    57→    // =========================================================================
    58→    const p5Container = document.getElementById('p5-container');
    59→    if (p5Container) {
    60→        new p5(function (p) {
    61→            const particles = [];
    62→            let cols, rows;
    63→            const scl = 35;
    64→            let flowField;
    65→            let zOff = 0;
    66→
    67→            function particleCount() {
    68→                const area = p.windowWidth * p.windowHeight;
    69→                // Fewer particles for a cleaner, more elegant look
    70→                return Math.min(Math.floor(area / 10000), 200);
    71→            }
    72→
    73→            p.setup = function () {
    74→                const cnv = p.createCanvas(p.windowWidth, p.windowHeight);
    75→                cnv.style('display', 'block');
    76→                p.colorMode(p.RGB, 255, 255, 255, 255);
    77→
    78→                cols = Math.floor(p.width / scl) + 1;
    79→                rows = Math.floor(p.height / scl) + 1;
    80→                flowField = new Array(cols * rows);
    81→
    82→                const count = particleCount();
    83→                for (let i = 0; i < count; i++) {
    84→                    particles.push(createParticle(p));
    85→                }
    86→            };
    87→
    88→            p.draw = function () {
    89→                // Faster fade = cleaner trails, no heavy buildup
    90→                p.background(250, 250, 250, 45);
    91→
    92→                // Build flow field
    93→                let xOff = 0;
    94→                for (let x = 0; x < cols; x++) {
    95→                    let yOff = 0;
    96→                    for (let y = 0; y < rows; y++) {
    97→                        const angle = p.noise(xOff, yOff, zOff) * p.TWO_PI * 2;
    98→                        const v = p5.Vector.fromAngle(angle);
    99→                        v.setMag(0.3);
   100→                        flowField[x + y * cols] = v;
   101→                        yOff += 0.06;
   102→                    }
   103→                    xOff += 0.06;
   104→                }
   105→                zOff += 0.0008;
   106→
   107→                for (const pt of particles) {
   108→                    const col = Math.floor(pt.pos.x / scl);
   109→                    const row = Math.floor(pt.pos.y / scl);
   110→                    const idx = col + row * cols;
   111→                    const force = flowField[idx];
   112→                    if (force) {
   113→                        pt.vel.add(force);
   114→                    }
   115→                    pt.vel.limit(pt.maxSpeed);
   116→                    pt.pos.add(pt.vel);
   117→
   118→                    // Wrap edges
   119→                    if (pt.pos.x > p.width)  pt.pos.x = 0;
   120→                    if (pt.pos.x < 0)        pt.pos.x = p.width;
   121→                    if (pt.pos.y > p.height)  pt.pos.y = 0;
   122→                    if (pt.pos.y < 0)        pt.pos.y = p.height;
   123→
   124→                    // Mint = 0, 220, 170 (slightly desaturated for elegance)
   125→                    // Yellow = 255, 196, 0
   126→                    const r = pt.isMint ? 0   : 255;
   127→                    const g = pt.isMint ? 210 : 196;
   128→                    const b = pt.isMint ? 170 : 0;
   129→
   130→                    // Core dot
   131→                    p.noStroke();
