/* ==========================================================================
   Base Design System - Protocodus
   ========================================================================== */
:root {
  /* Colors based on Logo */
  --clr-bg: #FAFAFA;
  --clr-text: #1A1A1A;
  --clr-yellow: #FFC400;
  --clr-mint: #00FFC3;
  --clr-black: #1A1A1A;
  --clr-white: #FFFFFF;
  --clr-grey: #888888;

  /* Typography */
  --font-primary: 'Space Grotesk', sans-serif;

  /* Layout & Spacing */
  --container-width: 1120px;
  --space-sm: 1rem;
  --space-md: 2rem;
  --space-lg: 4rem;
  --space-xl: 7rem;

  /* Aesthetics */
  --border-radius: 0px;
  --border-radius-pill: 999px;
  --border-width: 2.5px;
  --shadow-solid: 5px 5px 0px var(--clr-black);
  --shadow-solid-hover: 2px 2px 0px var(--clr-black);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Base Reset */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-primary);
  color: var(--clr-text);

