// =========================================================================
// Mobile Menu with Keyboard Support
// =========================================================================
const mobileMenuBtn = document.querySelector('.mobile-menu-btn');
const navLinks = document.querySelector('.nav-links');

function closeMenu() {
    mobileMenuBtn.classList.remove('active');
    navLinks.classList.remove('active');
    mobileMenuBtn.setAttribute('aria-expanded', 'false');
}

function openMenu() {
    mobileMenuBtn.classList.add('active');
    navLinks.classList.add('active');
    mobileMenuBtn.setAttribute('aria-expanded', 'true');
    // Focus first link when menu opens
    const firstLink = navLinks.querySelector('a');
    if (firstLink) setTimeout(() => firstLink.focus(), 0);
}

if (mobileMenuBtn && navLinks) {
    // Initialize aria-expanded
    mobileMenuBtn.setAttribute('aria-expanded', 'false');

    // Toggle menu on button click
    mobileMenuBtn.addEventListener('click', () => {
        const isOpen = mobileMenuBtn.classList.contains('active');
        if (isOpen) {
            closeMenu();
        } else {
            openMenu();
        }
    });

    // Close menu on link click
    const links = navLinks.querySelectorAll('a');
    links.forEach(link => {
        link.addEventListener('click', closeMenu);
        // Keyboard: Tab navigation with wraparound
        link.addEventListener('keydown', (e) => {
            if (e.key === 'Tab') {
                const isLastLink = link === links[links.length - 1];
                if (e.shiftKey && link === links[0]) {
                    // Shift+Tab on first link - focus button
                    e.preventDefault();
                    mobileMenuBtn.focus();
                } else if (!e.shiftKey && isLastLink) {
                    // Tab on last link - focus button
                    e.preventDefault();
                    mobileMenuBtn.focus();
                }
            }
        });
    });

    // Escape key closes menu
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && mobileMenuBtn.classList.contains('active')) {
            closeMenu();
            mobileMenuBtn.focus();
        }
    });

    // Focus trap: handle Tab from button when menu is open
    mobileMenuBtn.addEventListener('keydown', (e) => {
        if (e.key === 'Tab' && !e.shiftKey && mobileMenuBtn.classList.contains('active')) {
            e.preventDefault();
            const firstLink = navLinks.querySelector('a');
            if (firstLink) firstLink.focus();
        }
    });
}

