/* ==========================================================================
   Base Design System - Protocodus
   ========================================================================== */
:root {
  /* Colors based on Logo */
  --clr-bg: #FAFAFA;
  --clr-text: #1A1A1A;
  --clr-yellow: #FFC400;
  --clr-mint: #00FFC3;
  --clr-black: #1A1A1A;
  --clr-white: #FFFFFF;
  --clr-grey: #888888;
  --clr-text-muted: #555555;

  /* Typography */
  --font-primary: 'Space Grotesk', sans-serif;

  /* Typography Scale (1.2x ratio) */
  --fs-xs: 0.75rem;
  --fs-sm: 0.85rem;
  --fs-base: 1rem;
  --fs-md: 1.2rem;
  --fs-lg: 1.45rem;
  --fs-xl: 1.75rem;
  --fs-2xl: 2.1rem;
  --fs-3xl: 2.5rem;
  --fs-4xl: 3rem;
  --fs-5xl: 3.6rem;
  --fs-6xl: 4.3rem;
  --fs-7xl: 5.2rem;

  /* Line Heights */
  --lh-tight: 1.2;
  --lh-snug: 1.5;
  --lh-normal: 1.7;
  --lh-relaxed: 1.8;

  /* Letter Spacing */
  --ls-tight: -0.02em;
  --ls-normal: 0;
  --ls-wide: 1px;
  --ls-wider: 2px;

  /* Layout & Spacing (8px base) */
  --container-width: 1120px;
  --space-xs: 0.5rem;
  --space-sm: 1rem;
  --space-md: 1.5rem;
  --space-lg: 2rem;
  --space-xl: 3rem;
  --space-2xl: 4rem;
  --space-3xl: 5rem;
  --space-4xl: 7rem;

  /* Aesthetics */
  --border-radius: 0px;
  --border-radius-pill: 999px;
  --border-width: 2.5px;
  --shadow-sm: 1px 1px 0px var(--clr-black);
  --shadow-md: 2px 2px 0px var(--clr-black);
  --shadow-lg: 4px 4px 0px var(--clr-black);
  --shadow-xl: 6px 6px 0px var(--clr-black);
  --shadow-solid: 4px 4px 0px var(--clr-black);
  --shadow-solid-hover: 1px 1px 0px var(--clr-black);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);

  /* Focus State */
  --focus-outline: 2px solid var(--clr-yellow);
  --focus-outline-mint: 2px solid var(--clr-mint);
}

/* Base Reset */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-primary);
  color: var(--clr-text);
  line-height: var(--lh-normal);
  overflow-x: hidden;
  font-size: var(--fs-base);
}

/* Animated Background (p5.js) */
.bg-animation-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  z-index: -1;
  overflow: hidden;
  pointer-events: none;
  background-color: var(--clr-bg);
}

.bg-animation-container canvas {
  display: block;
  width: 100% !important;
  height: 100% !important;
}

a {
  text-decoration: none;
  color: inherit;
}

ul {
  list-style: none;
}

img,
svg {
  max-width: 100%;
  display: block;
}

.container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: 0 var(--space-lg);
}

.section {
  padding: var(--space-3xl) 0;
}

/* ==========================================================================
   Scroll Reveal Animation
   ========================================================================== */
.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s cubic-bezier(0.16, 1, 0.3, 1),
    transform 0.8s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* Stagger children */
.bento-grid .reveal:nth-child(2) {
  transition-delay: 0.1s;
}

.bento-grid .reveal:nth-child(3) {
  transition-delay: 0.2s;
}

.bento-grid .reveal:nth-child(4) {
  transition-delay: 0.3s;
}

/* ==========================================================================
   Buttons
   ========================================================================== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.65rem 1.75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: var(--ls-wide);
  border: var(--border-width) solid var(--clr-black);
  transition: var(--transition);
  font-size: var(--fs-sm);
  font-family: var(--font-primary);
  cursor: pointer;
  outline-offset: 2px;
}

.btn:focus-visible {
  outline: var(--focus-outline);
}

.btn-primary {
  background-color: var(--clr-yellow);
  color: var(--clr-black);
  box-shadow: var(--shadow-solid);
}

.btn-primary:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-mint);
}

.btn-primary:active {
  transform: translate(4px, 4px);
  box-shadow: none;
}

.btn-outline {
  background-color: var(--clr-white);
  color: var(--clr-black);
  box-shadow: var(--shadow-solid);
}

.btn-outline:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-yellow);
}

.btn-outline:active {
  transform: translate(4px, 4px);
  box-shadow: none;
}

.btn-lg {
  font-size: var(--fs-md);
  padding: 0.9rem 2.25rem;
}

/* ==========================================================================
   Navbar
   ========================================================================== */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  background-color: rgba(250, 250, 250, 0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: var(--border-width) solid var(--clr-black);
  z-index: 1000;
  transition: var(--transition);
}

.navbar.scrolled {
  padding: 0;
}

.nav-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 80px;
  padding: 0 var(--space-lg);
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.logo-img {
  height: 52px;
  width: auto;
}

.logo-text {
  font-size: var(--fs-xl);
  font-weight: 800;
  letter-spacing: var(--ls-wider);
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 2.5rem;
}

.nav-link {
  font-weight: 600;
  font-size: var(--fs-sm);
  text-transform: uppercase;
  letter-spacing: var(--ls-wide);
  position: relative;
  padding: 0.5rem 0;
  color: var(--clr-text);
  outline-offset: 2px;
}

.nav-link:focus-visible {
  outline: var(--focus-outline);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0%;
  height: 2.5px;
  background-color: var(--clr-yellow);
  transition: var(--transition);
}

.nav-link:hover::after {
  width: 100%;
}

.nav-btn {
  background-color: var(--clr-yellow);
  padding: 0.55rem 1.5rem;
  border: var(--border-width) solid var(--clr-black);
  font-weight: 700;
  box-shadow: var(--shadow-md);
  transition: var(--transition);
  text-transform: uppercase;
  font-size: var(--fs-sm);
  letter-spacing: var(--ls-wide);
  cursor: pointer;
  outline-offset: 2px;
}

.nav-btn:focus-visible {
  outline: var(--focus-outline);
}

.nav-btn:hover {
  box-shadow: var(--shadow-sm);
  transform: translate(1px, 1px);
  background-color: var(--clr-mint);
}

.nav-btn:active {
  transform: translate(2px, 2px);
  box-shadow: none;
}

.mobile-menu-btn {
  display: none;
  background: none;
  border: none;
  flex-direction: column;
  gap: 6px;
  cursor: pointer;
  padding: 8px;
  outline-offset: 2px;
}

.mobile-menu-btn:focus-visible {
  outline: var(--focus-outline);
}

.mobile-menu-btn span {
  display: block;
  width: 28px;
  height: 2.5px;
  background-color: var(--clr-black);
  transition: var(--transition);
  pointer-events: none;
}

/* ==========================================================================
   Hero Section
   ========================================================================== */
.hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding-top: 80px;
  position: relative;
  overflow: hidden;
}

.hero-container {
  display: flex;
  justify-content: center;
  position: relative;
  z-index: 1;
}

.hero-content {
  max-width: 680px;
}

.hero-title {
  font-size: var(--fs-7xl);
  font-weight: 900;
  line-height: var(--lh-tight);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--ls-tight);
  color: var(--clr-black);
}

.hero-subtitle {
  font-size: var(--fs-md);
  font-weight: 400;
  max-width: 520px;
  margin-bottom: var(--space-xl);
  color: var(--clr-text-muted);
  line-height: var(--lh-relaxed);
}

.hero-actions {
  display: flex;
  gap: var(--space-md);
}

/* ==========================================================================
   Section Headers
   ========================================================================== */
.section-header {
  text-align: center;
  margin-bottom: var(--space-3xl);
}

.section-title {
  font-size: var(--fs-5xl);
  font-weight: 900;
  margin-bottom: var(--space-lg);
  display: inline-block;
  position: relative;
  letter-spacing: var(--ls-tight);
}

.section-title::after {
  content: '';
  position: absolute;
  bottom: 6px;
  left: -6px;
  right: -6px;
  height: 35%;
  background-color: var(--clr-mint);
  z-index: -1;
  opacity: 0.5;
}

.section-desc {
  font-size: var(--fs-md);
  max-width: 560px;
  margin: 0 auto;
  color: var(--clr-text-muted);
  line-height: var(--lh-relaxed);
}

/* ==========================================================================
   Bento Grid — Services
   ========================================================================== */
.bento-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-lg);
}

.bento-card {
  background-color: var(--clr-white);
  border: var(--border-width) solid var(--clr-black);
  padding: var(--space-2xl);
  display: flex;
  flex-direction: column;
  box-shadow: var(--shadow-solid);
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.bento-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-xl);
}

.bento-card:focus-within {
  outline: var(--focus-outline);
  outline-offset: -4px;
}

.bento-card.bg-yellow {
  background-color: var(--clr-yellow);
}

.bento-card.bg-mint {
  background-color: var(--clr-mint);
}

.bento-icon {
  font-size: var(--fs-3xl);
  margin-bottom: var(--space-lg);
  color: var(--clr-black);
}

.bento-card h3 {
  font-size: var(--fs-2xl);
  font-weight: 800;
  margin-bottom: var(--space-md);
  line-height: var(--lh-tight);
}

.bento-card p {
  font-size: var(--fs-base);
  line-height: var(--lh-normal);
  margin-bottom: 0;
  flex-grow: 1;
  color: rgba(26, 26, 26, 0.8);
}

.bento-card.bg-yellow p,
.bento-card.bg-mint p {
  color: rgba(26, 26, 26, 0.85);
}

/* ==========================================================================
   About Section
   ========================================================================== */
.about-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-3xl);
  align-items: center;
}

.about-desc {
  font-size: var(--fs-md);
  margin-bottom: var(--space-lg);
  color: var(--clr-text-muted);
  line-height: var(--lh-relaxed);
}

.about-list {
  margin-bottom: var(--space-lg);
}

.about-list li {
  font-size: var(--fs-base);
  margin-bottom: var(--space-md);
  display: flex;
  align-items: center;
  gap: var(--space-md);
  font-weight: 500;
}

.check-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  background-color: var(--clr-mint);
  border: 2px solid var(--clr-black);
  font-weight: 800;
  font-size: var(--fs-sm);
  flex-shrink: 0;
}

/* About Stats Card */
.about-stats-card {
  background-color: var(--clr-black);
  color: var(--clr-white);
  border: var(--border-width) solid var(--clr-black);
  padding: var(--space-2xl);
  box-shadow: var(--shadow-xl);
  display: flex;
  flex-direction: column;
  gap: var(--space-2xl);
}

.stat-item {
  text-align: center;
}

.stat-number {
  display: block;
  font-size: var(--fs-6xl);
  font-weight: 900;
  letter-spacing: var(--ls-tight);
  line-height: var(--lh-tight);
  margin-bottom: var(--space-md);
  color: var(--clr-yellow);
}

.stat-label {
  display: block;
  font-size: var(--fs-sm);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: var(--ls-wider);
  color: rgba(255, 255, 255, 0.7);
}

.stat-divider {
  width: 40px;
  height: 2px;
  background-color: var(--clr-mint);
  margin: 0 auto;
  opacity: 0.5;
}

.mt-2 {
  margin-top: var(--space-lg);
}

/* ==========================================================================
   Contact Section
   ========================================================================== */
.bg-dark {
  background-color: var(--clr-black);
  color: var(--clr-white);
}

.title-light {
  color: var(--clr-white);
}

.title-light::after {
  background-color: var(--clr-mint);
  opacity: 0.35;
}

.contact-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: var(--space-2xl);
  padding: var(--space-2xl) 0;
}

.contact-name {
  font-size: var(--fs-xl);
  font-weight: 700;
  margin-bottom: var(--space-sm);
}

.contact-role {
  color: var(--clr-mint);
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: var(--ls-wider);
  font-size: var(--fs-sm);
  margin-bottom: var(--space-xl);
}

.contact-header p {
  font-size: var(--fs-lg);
  opacity: 0.85;
}

/* ==========================================================================
   Footer
   ========================================================================== */
.footer {
  border-top: var(--border-width) solid var(--clr-black);
  padding: var(--space-2xl) 0 var(--space-lg);
  background-color: var(--clr-white);
}

.footer-container {
  display: grid;
  grid-template-columns: 1fr;
  margin-bottom: var(--space-lg);
}

.footer-brand {
  text-align: center;
}

.footer-logo {
  justify-content: center;
}

.footer-logo-text {
  font-size: var(--fs-2xl);
  letter-spacing: var(--ls-wider);
}

.footer-tagline {
  margin: var(--space-md) auto 0;
  font-size: var(--fs-base);
  color: var(--clr-grey);
}

.footer-bottom {
  display: flex;
  justify-content: center;
  align-items: center;
  padding-top: var(--space-lg);
  border-top: 1.5px solid rgba(26, 26, 26, 0.12);
  font-weight: 500;
  font-size: var(--fs-sm);
  color: var(--clr-grey);
}

.footer-centered {
  grid-template-columns: 1fr;
  text-align: center;
}

.footer-bottom-centered {
  display: block;
  text-align: center;
}

/* ==========================================================================
   Media Queries
   ========================================================================== */
@media (max-width: 992px) {

  .hero-container,
  .about-container,
  .contact-container,
  .footer-container {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-content {
    text-align: center;
    margin: 0 auto;
  }

  .hero-subtitle {
    margin-left: auto;
    margin-right: auto;
  }

  .about-list li {
    justify-content: center;
  }

  .hero-actions {
    justify-content: center;
  }

  .hero-title {
    font-size: var(--fs-5xl);
  }

  .bento-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .about-stats-card {
    flex-direction: row;
    justify-content: center;
    max-width: 500px;
    margin: 0 auto;
  }

  .stat-divider {
    width: 2px;
    height: 40px;
  }
}

@media (max-width: 768px) {
  .container {
    padding: 0 var(--space-md);
  }

  .nav-container {
    padding: 0 var(--space-md);
  }

  .nav-container .logo-img {
    display: none;
  }

  .nav-links {
    display: none;
  }

  .nav-links.active {
    display: flex;
    flex-direction: column;
    position: absolute;
    top: 100%;
    left: 0;
    width: 100%;
    background-color: rgba(250, 250, 250, 0.98);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    padding: var(--space-lg);
    border-bottom: var(--border-width) solid var(--clr-black);
    align-items: center;
    gap: var(--space-md);
    z-index: 999;
  }

  .mobile-menu-btn {
    display: flex;
    position: relative;
    z-index: 1000;
  }

  .mobile-menu-btn.active span:nth-child(1) {
    transform: translateY(8.5px) rotate(45deg);
  }

  .mobile-menu-btn.active span:nth-child(2) {
    opacity: 0;
  }

  .mobile-menu-btn.active span:nth-child(3) {
    transform: translateY(-8.5px) rotate(-45deg);
  }

  .hero-title {
    font-size: var(--fs-4xl);
    letter-spacing: var(--ls-tight);
  }

  .hero-subtitle {
    font-size: var(--fs-base);
  }

  .section-title {
    font-size: var(--fs-4xl);
  }

  .bento-grid {
    grid-template-columns: 1fr;
    gap: var(--space-md);
  }

  .bento-card {
    padding: var(--space-lg);
  }

  .about-stats-card {
    flex-direction: column;
    max-width: 100%;
  }

  .stat-divider {
    width: 40px;
    height: 2px;
  }

  .footer-logo-text {
    font-size: var(--fs-2xl);
  }

  .footer-bottom {
    flex-direction: column;
    gap: var(--space-md);
    text-align: center;
  }

  .btn-lg {
    font-size: var(--fs-sm);
    padding: 0.65rem 1.75rem;
  }

  .section {
    padding: var(--space-2xl) 0;
  }
}

@media (max-width: 480px) {
  .container {
    padding: 0 var(--space-sm);
  }

  .hero-title {
    font-size: var(--fs-3xl);
    letter-spacing: var(--ls-tight);
  }

  .hero-subtitle {
    font-size: var(--fs-base);
  }

  .hero-actions {
    flex-direction: column;
    gap: var(--space-sm);
  }

  .bento-card {
    padding: var(--space-md);
  }

  .section {
    padding: var(--space-2xl) 0;
  }

  .section-title {
    font-size: var(--fs-3xl);
  }

  .btn {
    padding: 0.6rem 1.5rem;
    font-size: var(--fs-xs);
  }

  .btn-lg {
    padding: 0.75rem 1.5rem;
    font-size: var(--fs-sm);
  }
}

